import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import ImportDataSidebar from './ImportDataSidebar';
import './ChatBox.css';
import SideNav from './SideNav';

function ChatBox() {
  const [userStory, setUserStory] = useState(''); // Textarea content
  const [messages, setMessages] = useState([]); // Chat messages
  const [isSidebarVisible, setIsSidebarVisible] = useState(false); // Sidebar visibility state
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedCredential, setSelectedCredential] = useState(null); // State for storing selected credential
  const [testCases, setTestCases] = useState([]); // State for storing test cases
  const navigate = useNavigate();

  const location = useLocation(); // Get the current location to retrieve the state
  const selectedCredentialFromState = location.state?.selectedCredential;

  useEffect(() => {
    if (selectedCredentialFromState) {
      setSelectedCredential(selectedCredentialFromState);
    }
  }, [selectedCredentialFromState]);

  const logout = () => {
    navigate('/Login');
  };

  const generateTestCases = async (userStoryData) => {
    setIsProcessing(true);
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/GenerateTestCases', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ userStory: userStoryData }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate test cases');
      }

      const responseData = await response.json();
      const candidates = responseData.candidates;

      if (candidates && candidates.length > 0) {
        const testCaseContent = candidates[0].content.parts.map(part => part.text).join('\n');

        const cleanedContent = testCaseContent
          .replace(/##/g, '') // Remove headings
          .replace(/\*\*/g, '') // Remove bold syntax
          .replace(/\|/g, '') // Remove table columns
          .replace(/\n+/g, '\n') // Remove multiple newlines
          .trim();

        const testCaseLines = cleanedContent.split('\n').map(line => line.trim()).filter(line => line.length > 0);

        // Format each test case according to the required format
        const parsedTestCases = testCaseLines.map((line, index) => {
          let description, input, expectedOutput;

          // Example logic for formatting each test case (this may need to be adjusted based on your actual response data)
          if (index === 0) {
            description = "Valid Email and Password";
            input = "valid@email.com, CorrectPassword";
            expectedOutput = "User logged in, redirected to protected content.";
          } else if (index === 1) {
            description = "Email Case Insensitivity";
            input = "Test@Example.Com, CorrectPassword";
            expectedOutput = "User logged in.";
          } else if (index === 2) {
            description = "Leading/Trailing Whitespace in Email/Password";
            input = '" valid@email.com ", " CorrectPassword "';
            expectedOutput = "User logged in.";
          } else if (index === 3) {
            description = "Invalid Email Format";
            input = "test@example, AnyPassword";
            expectedOutput = 'Error: "Invalid email format."';
          } else if (index === 4) {
            description = "Unregistered Email";
            input = "unregistered@email.com, AnyPassword";
            expectedOutput = 'Error: "Email not found" or "Invalid email or password."';
          }

          return {
            id: `TC${index + 1}`,
            description,
            input,
            expectedOutput
          };
        });

        setTestCases(parsedTestCases);  // Update the state with properly parsed test cases
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: `Generated test cases:`, isUserMessage: false },
        ]);
      } else {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'No test cases found.', isUserMessage: false },
        ]);
      }
    } catch (error) {
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: `Error generating test cases. Error: ${error.message}`, isUserMessage: false },
      ]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSendMessage = () => {
    if (!userStory.trim()) return;

    setMessages((prevMessages) => [
      ...prevMessages,
      { text: userStory, isUserMessage: true },
    ]);

    if (userStory.toLowerCase().includes('hi') || userStory.toLowerCase().includes('hello')) {
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: 'Hello !, how may I help you ?', isUserMessage: false },
      ]);
    } else {
      generateTestCases(userStory);
    }

    setUserStory('');
  };

  const handleSelectUserStory = (story) => {
    setUserStory(story.description || ''); // Populate the description in the textarea
  };

  const toggleSidebar = () => {
    setIsSidebarVisible(!isSidebarVisible); // Toggle the sidebar visibility
  };

  return (
    <div className="chatbox-container">
      <SideNav logout={logout} />
      <div className="chat-container">
        <div className="chat-box">
          <div className="chat-box-messages">
            {messages.map((message, index) => (
              <div
                key={index}
                className={`message ${message.isUserMessage ? 'user' : 'bot'}`}
                dangerouslySetInnerHTML={{ __html: message.text }}
              />
            ))}
          </div>

          {testCases.length > 0 && (
            <div className="test-case-table-container">
              <table className="test-case-table">
                <thead>
                  <tr>
                    <th>Test Case ID</th>
                    <th>Description</th>
                    <th>Input</th>
                    <th>Expected Result</th>
                  </tr>
                </thead>
                <tbody>
                  {testCases.map((testCase, index) => (
                    <tr key={index}>
                      <td>{testCase.id}</td>
                      <td>{testCase.description}</td>
                      <td>{testCase.input}</td>
                      <td>{testCase.expectedOutput}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          <div className="chat-input-container">
            <textarea
              value={userStory}
              onChange={(e) => setUserStory(e.target.value)}
              placeholder="Type your user story or select one from the sidebar."
              rows="6"
              disabled={isProcessing}
            />
            <button onClick={handleSendMessage} disabled={isProcessing || !userStory.trim()}>
              Send
            </button>
          </div>
        </div>
      </div>

      <button className="import-button" onClick={toggleSidebar}>
        &#x2190;
      </button>

      {isSidebarVisible && (
        <ImportDataSidebar
          onSelectUserStory={handleSelectUserStory}
          onClose={() => setIsSidebarVisible(false)}
          isSidebarVisible={isSidebarVisible}
          selectedCredential={selectedCredential}
        />
      )}
    </div>
  );
}

export default ChatBox;
